// Convert the binary from Google Drive into base64 + filename for the MCP tool
const binary = item.binary.data;
return {
  json: {
    chatInput: $('Chat Trigger').first().json.chatInput,
    filename: binary.fileName || 'project.mpp',
    mppBase64: binary.data  // n8n already stores binary as base64
  }
};

// If the agent produced an HTML dashboard (build_dashboard tool result), extract it
// and surface as a binary on a second output branch.
const agentOutput = $input.first().json;
const result = { json: { reply: agentOutput.output || agentOutput.text || agentOutput } };

// Look for a tool-call result with file_b64 shape in the agent's intermediate steps
const steps = agentOutput.intermediateSteps || [];
for (const step of steps) {
  const obs = step.observation;
  if (obs && obs.file_b64 && obs.filename) {
    result.binary = {
      data: {
        data: obs.file_b64,
        fileName: obs.filename,
        mimeType: obs.filename.endsWith('.html') ? 'text/html' :
                  obs.filename.endsWith('.xml')  ? 'application/xml' :
                  'application/octet-stream'
      }
    };
    break;
  }
}
return result;
